export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Array<Record<string, any>>;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Array<Record<string, any>>>;
}

const NUMBER_REGEX = /^-?\d+(?:\.\d+)?$/;

function coerceValue(raw: string): any {
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (NUMBER_REGEX.test(trimmed)) {
    return trimmed.includes('.') ? parseFloat(trimmed) : parseInt(trimmed, 10);
  }

  return raw;
}

interface ParsedRowOutcome {
  fields: string[];
  error?: string;
}

function parseRow(row: string, delimiter: string, quoteChar: string): ParsedRowOutcome {
  const fields: string[] = [];
  let buffer = '';
  let inQuotes = false;

  for (let i = 0; i < row.length; i++) {
    const current = row[i];

    if (current === quoteChar) {
      if (inQuotes) {
        if (row[i + 1] === quoteChar) {
          buffer += quoteChar;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        inQuotes = true;
      }
      continue;
    }

    if (current === delimiter && !inQuotes) {
      fields.push(buffer);
      buffer = '';
      continue;
    }

    buffer += current;
  }

  fields.push(buffer);

  const outcome: ParsedRowOutcome = { fields };

  if (inQuotes) {
    outcome.error = 'Unclosed quoted field';
  }

  return outcome;
}

function splitLines(input: string, separator?: string): string[] {
  if (separator !== undefined) {
    if (separator === '') {
      return [input];
    }
    return input.split(separator);
  }
  return input.split(/\r\n|\n|\r/);
}

function buildCSVResult(
  headers: string[],
  rows: Array<Record<string, any>>,
  errors: CSVError[]
): CSVResult {
  const baseRows = rows;

  return {
    rows: baseRows,
    headers,
    errors,
    filter(predicate) {
      return baseRows.filter(predicate);
    },
    sum(column) {
      let total = 0;
      for (const row of baseRows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
        }
      }
      return total;
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of baseRows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return baseRows.length;
    },
    groupBy(column) {
      const map = new Map<any, Array<Record<string, any>>>();
      for (const row of baseRows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator;

  const trimmedInput = input ?? '';
  if (trimmedInput.trim().length === 0) {
    return buildCSVResult([], [], []);
  }

  const lines = splitLines(trimmedInput, lineSeparator);
  let headerLineIndex: number | null = null;

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim().length === 0) {
      continue;
    }
    headerLineIndex = i;
    break;
  }

  if (headerLineIndex === null) {
    return buildCSVResult([], [], []);
  }

  const headerLine = lines[headerLineIndex];
  const headerNum = headerLineIndex + 1;
  const headerOutcome = parseRow(headerLine, delimiter, quoteChar);
  const headers = headerOutcome.fields.map((h) => h);
  const errors: CSVError[] = [];

  if (headerOutcome.error) {
    errors.push({ row: headerNum, message: headerOutcome.error });
  }

  const rows: Array<Record<string, any>> = [];

  for (let lineIndex = headerLineIndex + 1; lineIndex < lines.length; lineIndex++) {
    const rawLine = lines[lineIndex];
    const realLineNumber = lineIndex + 1;

    if (rawLine.trim().length === 0) {
      continue;
    }

    const parsed = parseRow(rawLine, delimiter, quoteChar);
    if (parsed.error) {
      errors.push({ row: realLineNumber, message: parsed.error });
      continue;
    }

    if (parsed.fields.length !== headers.length) {
      errors.push({
        row: realLineNumber,
        message: `Expected ${headers.length} fields, got ${parsed.fields.length}`,
      });
      continue;
    }

    const row: Record<string, any> = {};
    for (let i = 0; i < headers.length; i++) {
      row[headers[i]] = coerceValue(parsed.fields[i]);
    }

    rows.push(row);
  }

  return buildCSVResult(headers, rows, errors);
}

import { parseCSV } from './csv-parser';

const assert = (condition: boolean, message?: string) => {
  if (!condition) {
    throw new Error(message || 'Assertion failed');
  }
};

const assertEqual = (actual: any, expected: any, message?: string) => {
  if (actual !== expected) {
    throw new Error(message || `Expected ${JSON.stringify(expected)}, got ${JSON.stringify(actual)}`);
  }
};

const assertDeepEqual = (actual: any, expected: any, message?: string) => {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(message || `Deep equality failed. Expected ${expectedJson}, got ${actualJson}`);
  }
};

const runTests = () => {
  // Basic parsing
  const basicInput = 'name,age\nAlice,30\nBob,25';
  const basicResult = parseCSV(basicInput);
  assertDeepEqual(basicResult.headers, ['name', 'age'], 'Headers should match');
  assertEqual(basicResult.count(), 2, 'Should parse two rows');
  assertDeepEqual(basicResult.rows[0], { name: 'Alice', age: 30 });
  assertDeepEqual(basicResult.rows[1], { name: 'Bob', age: 25 });

  // Quoted fields with commas
  const quotedInput = 'name,notes\nJohn,"Loves, commas"';
  const quotedResult = parseCSV(quotedInput);
  assertEqual(quotedResult.rows[0].notes, 'Loves, commas');

  // Escaped quotes
  const escapedInput = 'quote\n"She said ""Hi"""';
  const escapedResult = parseCSV(escapedInput);
  assertEqual(escapedResult.rows[0].quote, 'She said "Hi"');

  // Custom delimiters and quote characters
  const customInput = "name;note\n'Bob';'likes;semi'";
  const customResult = parseCSV(customInput, { delimiter: ';', quoteChar: "'" });
  assertEqual(customResult.headers[0], 'name');
  assertEqual(customResult.rows[0].note, 'likes;semi');

  // Type coercion
  const typeInput = 'num,float,bool,nullVal,empty,string\n1,2.5,true,NULL,,Hello\n-2,3.14,FALSE,null, ,World';
  const typeResult = parseCSV(typeInput);
  assertEqual(typeResult.rows[0].num, 1);
  assertEqual(typeResult.rows[0].float, 2.5);
  assertEqual(typeResult.rows[0].bool, true);
  assertEqual(typeResult.rows[0].nullVal, null);
  assertEqual(typeResult.rows[0].empty, null);
  assertEqual(typeResult.rows[0].string, 'Hello');
  assertEqual(typeResult.rows[1].num, -2);
  assertEqual(typeResult.rows[1].float, 3.14);
  assertEqual(typeResult.rows[1].bool, false);
  assertEqual(typeResult.rows[1].nullVal, null);
  assertEqual(typeResult.rows[1].empty, null);
  assertEqual(typeResult.rows[1].string, 'World');

  // Malformed rows
  const malformedInput = 'name,age\nAlice,30\nBob\nCharlie,25,extra\n"Broken';
  const malformedResult = parseCSV(malformedInput);
  assertEqual(malformedResult.errors.length, 3);
  assertEqual(malformedResult.errors[0].row, 3);
  assertEqual(malformedResult.errors[1].row, 4);
  assertEqual(malformedResult.errors[2].row, 5);

  // Filter functionality
  const filterInput = 'name,age\nAlice,30\nBob,25\nCharlie,35';
  const filterResult = parseCSV(filterInput);
  const filtered = filterResult.filter((row) => row.age > 30);
  assertEqual(filtered.length, 1);
  assertEqual(filtered[0].name, 'Charlie');

  // Aggregation methods
  const aggregateResult = parseCSV('name,team,score\nAlice,A,10\nBob,B,20\nAna,A,30');
  assertEqual(aggregateResult.sum('score'), 60);
  assertEqual(aggregateResult.average('score'), 20);
  assertEqual(aggregateResult.count(), 3);
  const groups = aggregateResult.groupBy('team');
  assertEqual(groups.size, 2);
  assertEqual(groups.get('A')!.length, 2);

  // Edge cases
  const emptyResult = parseCSV('');
  assertEqual(emptyResult.count(), 0);
  assertDeepEqual(emptyResult.headers, []);

  const singleCol = parseCSV('value\n42');
  assertEqual(singleCol.count(), 1);
  assertEqual(singleCol.rows[0].value, 42);

  const largeHeader = 'id,text';
  const longValue = 'x'.repeat(5000);
  const largeInput = `${largeHeader}\n1,"${longValue}"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].text, longValue);
};

runTests();
console.log('All csv-parser tests passed');

