};

const runTests = () => {
  // Basic parsing
  const basicInput = `name,age
Alice,30
Bob,25`;
  const basicResult = parseCSV(basicInput);
  assertDeepEqual(basicResult.headers, ['name', 'age'], 'Headers should match');
  assertEqual(basicResult.count(), 2, 'Should parse two rows');
  assertDeepEqual(basicResult.rows[0], { name: 'Alice', age: 30 });
  assertDeepEqual(basicResult.rows[1], { name: 'Bob', age: 25 });

  // Quoted fields with commas
  const quotedInput = `name,notes
John,"Loves, commas"`;
  const quotedResult = parseCSV(quotedInput);
  assertEqual(quotedResult.rows[0].notes, 'Loves, commas');

  // Escaped quotes
  const escapedInput = `quote
"She said ""Hi"""`;
  const escapedResult = parseCSV(escapedInput);
  assertEqual(escapedResult.rows[0].quote, 'She said "Hi"');

  // Custom delimiters and quote characters
  const customInput = `name;note
'Bob';'likes;semi'`;
  const customResult = parseCSV(customInput, { delimiter: ';', quoteChar: "'" });
  assertEqual(customResult.headers[0], 'name');
  assertEqual(customResult.rows[0].note, 'likes;semi');

  // Type coercion
  const typeInput = `num,float,bool,nullVal,empty,string
1,2.5,true,NULL,,Hello
-2,3.14,FALSE,null, ,World`;
  const typeResult = parseCSV(typeInput);
  assertEqual(typeResult.rows[0].num, 1);
  assertEqual(typeResult.rows[0].float, 2.5);
  assertEqual(typeResult.rows[0].bool, true);
  assertEqual(typeResult.rows[0].nullVal, null);
  assertEqual(typeResult.rows[0].empty, null);
  assertEqual(typeResult.rows[0].string, 'Hello');
  assertEqual(typeResult.rows[1].num, -2);
  assertEqual(typeResult.rows[1].float, 3.14);
  assertEqual(typeResult.rows[1].bool, false);
  assertEqual(typeResult.rows[1].nullVal, null);
  assertEqual(typeResult.rows[1].empty, null);
  assertEqual(typeResult.rows[1].string, 'World');

  // Malformed rows
  const malformedInput = `name,age
Alice,30
Bob
Charlie,25,extra
"Broken`;
  const malformedResult = parseCSV(malformedInput);
  assertEqual(malformedResult.errors.length, 3);
  assertEqual(malformedResult.errors[0].row, 3);
  assertEqual(malformedResult.errors[1].row, 4);
  assertEqual(malformedResult.errors[2].row, 5);

  // Filter functionality
  const filterInput = `name,age
Alice,30
Bob,25
Charlie,35`;
  const filterResult = parseCSV(filterInput);
  const filtered = filterResult.filter((row) => row.age > 30);
  assertEqual(filtered.length, 1);
  assertEqual(filtered[0].name, 'Charlie');

  // Aggregation methods
  const aggregateResult = parseCSV(`name,team,score
Alice,A,10
Bob,B,20
Ana,A,30`);
  assertEqual(aggregateResult.sum('score'), 60);
  assertEqual(aggregateResult.average('score'), 20);
  assertEqual(aggregateResult.count(), 3);
  const groups = aggregateResult.groupBy('team');
  assertEqual(groups.size, 2);
  assertEqual(groups.get('A')!.length, 2);

  // Edge cases
  const emptyResult = parseCSV('');
  assertEqual(emptyResult.count(), 0);
  assertDeepEqual(emptyResult.headers, []);

  const singleCol = parseCSV(`value
42`);
  assertEqual(singleCol.count(), 1);
  assertEqual(singleCol.rows[0].value, 42);

  const largeHeader = 'id,text';
  const longValue = 'x'.repeat(5000);
  const largeInput = `${largeHeader}
1,"${longValue}"`;
  const largeResult = parseCSV(largeInput);
  assertEqual(largeResult.rows[0].text, longValue);
};

runTests();
console.log('All csv-parser tests passed');

