export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): Array<Record<string, any>>;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Array<Record<string, any>>>;
}

const NUMBER_REGEX = /^-?\d+(?:\.\d+)?$/;

function coerceValue(raw: string): any {
  const trimmed = raw.trim();
  if (trimmed === '') {
    return null;
  }

  const lower = trimmed.toLowerCase();
  if (lower === 'null') {
    return null;
  }

  if (lower === 'true') {
    return true;
  }

  if (lower === 'false') {
    return false;
  }

  if (NUMBER_REGEX.test(trimmed)) {
    return trimmed.includes('.') ? parseFloat(trimmed) : parseInt(trimmed, 10);
  }

  return raw;
}

interface ParsedRowOutcome {
  fields: string[];
  error?: string;
}

function parseRow(row: string, delimiter: string, quoteChar: string): ParsedRowOutcome {
  const fields: string[] = [];
  let buffer = '';
  let inQuotes = false;

  for (let i = 0; i < row.length; i++) {
    const current = row[i];

    if (current === quoteChar) {
      if (inQuotes) {
        if (row[i + 1] === quoteChar) {
          buffer += quoteChar;
          i += 1;
        } else {
          inQuotes = false;
        }
      } else {
        inQuotes = true;
      }
      continue;
    }

    if (current === delimiter && !inQuotes) {
      fields.push(buffer);
      buffer = '';
      continue;
    }

    buffer += current;
  }

  fields.push(buffer);

  const outcome: ParsedRowOutcome = { fields };

  if (inQuotes) {
    outcome.error = 'Unclosed quoted field';
  }

  return outcome;
}

function splitLines(input: string, separator?: string): string[] {
  if (separator !== undefined) {
    if (separator === '') {
      return [input];
    }
    return input.split(separator);
  }
  return input.split(/\r\n|\n|\r/);
}

function buildCSVResult(
  headers: string[],
  rows: Array<Record<string, any>>,
  errors: CSVError[]
): CSVResult {
  const baseRows = rows;

  return {
    rows: baseRows,
    headers,
    errors,
    filter(predicate) {
      return baseRows.filter(predicate);
    },
    sum(column) {
      let total = 0;
      for (const row of baseRows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
        }
      }
      return total;
    },
    average(column) {
      let total = 0;
      let count = 0;
      for (const row of baseRows) {
        const value = row[column];
        if (typeof value === 'number' && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return baseRows.length;
    },
    groupBy(column) {
      const map = new Map<any, Array<Record<string, any>>>();
      for (const row of baseRows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ',';
  const quoteChar = options.quoteChar ?? '"';
  const lineSeparator = options.lineSeparator;

  const trimmedInput = input ?? '';
  if (trimmedInput.trim().length === 0) {
    return buildCSVResult([], [], []);
  }

  const lines = splitLines(trimmedInput, lineSeparator);
  let headerLineIndex: number | null = null;

  for (let i = 0; i < lines.length; i++) {
    if (lines[i].trim().length === 0) {
      continue;
    }
    headerLineIndex = i;
    break;
  }

  if (headerLineIndex === null) {
    return buildCSVResult([], [], []);
  }

  const headerLine = lines[headerLineIndex];
  const headerNum = headerLineIndex + 1;
  const headerOutcome = parseRow(headerLine, delimiter, quoteChar);
  const headers = headerOutcome.fields.map((h) => h);
  const errors: CSVError[] = [];

  if (headerOutcome.error) {
    errors.push({ row: headerNum, message: headerOutcome.error });
  }

  const rows: Array<Record<string, any>> = [];

  for (let lineIndex = headerLineIndex + 1; lineIndex < lines.length; lineIndex++) {
    const rawLine = lines[lineIndex];
    const realLineNumber = lineIndex + 1;

    if (rawLine.trim().length === 0) {
      continue;
    }

    const parsed = parseRow(rawLine, delimiter, quoteChar);
    if (parsed.error) {
      errors.push({ row: realLineNumber, message: parsed.error });
      continue;
    }

    if (parsed.fields.length !== headers.length) {
      errors.push({
        row: realLineNumber,
        message: `Expected ${headers.length} fields, got ${parsed.fields.length}`,
      });
      continue;
    }

    const row: Record<string, any> = {};
    for (let i = 0; i < headers.length; i++) {
      row[headers[i]] = coerceValue(parsed.fields[i]);
    }

    rows.push(row);
  }

  return buildCSVResult(headers, rows, errors);
}
